            elif device == 'cuda':
                _, U = torch.linalg.eigh(S)
                idx = np.array(np.arange(d)[::-1][:k])
                P = U[:, idx]

            if verbose > 1:
                print('BCD svd computation time:', time.time() - t1_bcd)

        elif method == 'MM':
            # majorization-minimization
            t0_mm = time.time()

            if device == 'cpu':
                if svd_fct_cpu == 'scipy':
